{
  "title": "ब्लॉक एलिमेंट को लंबवत केंद्रित करना",
  "group": "लेआउट: केंद्रित करना",
  "options": [
    {
      "text": "align-items: center;"
    },
    {
      "text": "justify-content: center;"
    },
    {
      "text": "align-content: center;"
    },
    {
      "text": "margin: auto;"
    },
    {
      "text": "margin: 0 auto;"
    }
  ],
  "questionProse": [
    "आधुनिक फ्लो लेआउट में ब्लॉक कंटेनर के भीतर सामग्री को लंबवत कैसे केंद्रित करें?"
  ],
  "explanationProse": [
    "`align-content` का उपयोग करना आधुनिक तरीका है ब्लॉक कंटेनर की सामग्री को फ्लो लेआउट में लंबवत केंद्रित करने का।\n\n`align-items` और `justify-content` प्रॉपर्टी flexbox और grid लेआउट के लिए हैं, फ्लो के लिए नहीं।\n\n`margin: 0 auto;` और `margin: auto;` दोनों ब्लॉक एलिमेंट को क्षैतिज रूप से केंद्रित करते हैं, लेकिन लंबवत नहीं।"
  ]
}
